# Core shape module - demonstrates cross-module inheritance and interfaces
from geo_utils import Point, Color, ShapeType, IMeasurable, IScalable

# Abstract base class for all shapes
@abstract
class Shape(IMeasurable):
    color: Color
    center: Point

    def __init__(self, color: Color, center: Point):
        self.color = color
        self.center = center

    @abstract
    def get_area(self) -> float: ...

    @abstract
    def get_perimeter(self) -> float: ...

    @virtual
    def describe(self) -> str:
        return "A generic shape"

    @virtual
    def get_shape_type(self) -> ShapeType:
        return ShapeType.RECTANGLE

# Concrete shape implementations
class Rectangle(Shape, IScalable):
    width: float
    height: float

    def __init__(self, width: float, height: float, color: Color, center: Point):
        super().__init__(color, center)
        self.width = width
        self.height = height

    @override
    def get_area(self) -> float:
        return self.width * self.height

    @override
    def get_perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def describe(self) -> str:
        return f"A rectangle with width {self.width} and height {self.height}"

    @override
    def get_shape_type(self) -> ShapeType:
        return ShapeType.RECTANGLE

    def scale(self, factor: float) -> float:
        self.width = self.width * factor
        self.height = self.height * factor
        return self.get_area()

class Circle(Shape, IScalable):
    radius: float

    def __init__(self, radius: float, color: Color, center: Point):
        super().__init__(color, center)
        self.radius = radius

    @override
    def get_area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def get_perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def describe(self) -> str:
        return f"A circle with radius {self.radius}"

    @override
    def get_shape_type(self) -> ShapeType:
        return ShapeType.CIRCLE

    def scale(self, factor: float) -> float:
        self.radius = self.radius * factor
        return self.get_area()

# Static factory class for creating shapes
class ShapeFactory:
    @static
    def create_rectangle(width: float, height: float) -> Rectangle:
        center: Point = Point(0.0, 0.0)
        return Rectangle(width, height, Color.BLUE, center)

    @static
    def create_circle(radius: float) -> Circle:
        center: Point = Point(0.0, 0.0)
        return Circle(radius, Color.GREEN, center)

# Generic collection wrapper
class ShapeCollection[T]:
    items: list[T]

    def __init__(self):
        self.items = []

    def add(self, item: T) -> None:
        self.items.append(item)

    def get_count(self) -> int:
        return len(self.items)

    def get_total_area(self) -> float:
        total: float = 0.0
        for shape in self.items:
            # Access through IMeasurable interface
            measurable: IMeasurable = shape
            total = total + measurable.get_area()
        return total

