# Module for comparing shapes - demonstrates cross-module method dispatch
from shapes import Shape, Rectangle, Circle
from geo_utils import Point, Color

# Comparator class using shapes from another module
class ShapeComparer:
    def compare_by_area(self, s1: Shape, s2: Shape) -> str:
        area1: float = s1.get_area()
        area2: float = s2.get_area()
        if area1 > area2:
            return "First is larger"
        elif area2 > area1:
            return "Second is larger"
        else:
            return "Equal area"

    def find_largest(self, shapes: list[Shape]) -> Shape | None:
        if len(shapes) == 0:
            return None
        largest: Shape = shapes[0]
        i: int = 1
        while i < len(shapes):
            if shapes[i].get_area() > largest.get_area():
                largest = shapes[i]
            i = i + 1
        return largest

# Class that uses Shape's interface implementation
class ShapeAnalyzer:
    def analyze_shape(self, shape: Shape) -> str:
        desc: str = shape.describe()
        area: float = shape.get_area()
        perimeter: float = shape.get_perimeter()
        return f"Desc: {desc}, Area: {area}, Perimeter: {perimeter}"
